package genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program_assignment.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program_assignment.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program_assignment.mapper.VehicleMaintenanceProgramAssignmentMapper; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program_assignment.repository.VehicleMaintenanceProgramAssignmentRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleMaintenanceProgramAssignmentService { private final VehicleMaintenanceProgramAssignmentRepository repository; private final VehicleMaintenanceProgramAssignmentMapper mapper; public VehicleMaintenanceProgramAssignmentService(VehicleMaintenanceProgramAssignmentRepository repository,VehicleMaintenanceProgramAssignmentMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleMaintenanceProgramAssignmentResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleMaintenanceProgramAssignmentResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("VehicleMaintenanceProgramAssignment", String.valueOf(id))); } public VehicleMaintenanceProgramAssignmentResponse create(VehicleMaintenanceProgramAssignmentUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleMaintenanceProgramAssignmentResponse update(UUID id,VehicleMaintenanceProgramAssignmentUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("VehicleMaintenanceProgramAssignment", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("VehicleMaintenanceProgramAssignment", String.valueOf(id)); } }
